import React, { useEffect, useMemo, useState } from 'react'
import '../../styles/technician/technician-ponds.css'
import { pondService } from '../../services/api'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'

const formatRoundedNumber = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  const numberValue = Number(value)
  if (Number.isNaN(numberValue)) return value
  return String(Math.round(numberValue))
}

const formatDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value
  return date.toLocaleString('vi-VN')
}

const normalizeUpper = (value) => String(value || '').trim().toUpperCase()

const TechnicianPonds = () => {
  const { user } = useAuth()
  const [ponds, setPonds] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [usageFilter, setUsageFilter] = useState('ALL')
  const [currentPage, setCurrentPage] = useState(1)
  const [pageSize, setPageSize] = useState(10)
  const [selectedPond, setSelectedPond] = useState(null)

  useEffect(() => { fetchData() }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const res = await pondService.getAllPonds()
      setPonds(res?.data?.data || [])
    } catch (err) {
      showToast({ title: err?.response?.data?.message || 'Không tải được dữ liệu ao', type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  const CHART_COLORS = ['#0ea5e9', '#22c55e', '#f59e0b', '#ef4444', '#a855f7', '#14b8a6']

  const normalizeUpper = (value) => String(value || '').trim().toUpperCase()

  const getPondStatusLabel = (status) => {
    switch (normalizeUpper(status)) {
      case 'DANG_NUOI':
        return 'Đang nuôi'
      case 'DANG_CAI_TAO':
        return 'Đang cải tạo'
      case 'TAM_NGUNG':
        return 'Tạm ngưng'
      default:
        return status || '-'
    }
  }

  const getUsageStatusLabel = (status) => {
    switch (normalizeUpper(status)) {
      case 'HOAT_DONG':
        return 'Hoạt động'
      case 'NGUNG_SU_DUNG':
        return 'Ngưng sử dụng'
      default:
        return status || '-'
    }
  }

  const getPondStatusClass = (status) => {
    switch (normalizeUpper(status)) {
      case 'DANG_NUOI':
        return 'owner-ponds_status owner-ponds_status--farming'
      case 'DANG_CAI_TAO':
        return 'owner-ponds_status owner-ponds_status--renovating'
      case 'TAM_NGUNG':
        return 'owner-ponds_status owner-ponds_status--paused'
      default:
        return 'owner-ponds_status'
    }
  }

  const getUsageStatusClass = (status) => {
    if (normalizeUpper(status) === 'HOAT_DONG') {
      return 'status-badge status-active'
    }
    return 'status-badge status-inactive'
  }

  const summary = useMemo(() => {
    const initial = { total: 0, farming: 0, renovating: 0, paused: 0, activeUsage: 0, inactiveUsage: 0 }
    for (const p of ponds) {
      initial.total += 1
      const s = normalizeUpper(p.status)
      const u = normalizeUpper(p.usage_status)
      if (s === 'DANG_NUOI') initial.farming += 1
      if (s === 'DANG_CAI_TAO') initial.renovating += 1
      if (s === 'TAM_NGUNG') initial.paused += 1
      if (u === 'HOAT_DONG') initial.activeUsage += 1
      if (u === 'NGUNG_SU_DUNG') initial.inactiveUsage += 1
    }
    return initial
  }, [ponds])

  const filtered = useMemo(() => {
    const s = String(searchTerm || '').trim().toLowerCase()
    return ponds.filter((p) => {
      if (s && !String(p.pond_name || '').toLowerCase().includes(s)) return false
      if (statusFilter !== 'ALL' && normalizeUpper(p.status) !== statusFilter) return false
      if (usageFilter !== 'ALL' && normalizeUpper(p.usage_status) !== usageFilter) return false
      return true
    }).sort((a,b)=> new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
  }, [ponds, searchTerm, statusFilter, usageFilter])

  const pondStatusChartData = useMemo(() => [
    { label: 'Đang nuôi', value: summary.farming, color: '#22c55e' },
    { label: 'Đang cải tạo', value: summary.renovating, color: '#f59e0b' },
    { label: 'Tạm ngưng', value: summary.paused, color: '#0ea5e9' },
  ], [summary])

  const pondStatusTotal = useMemo(() => pondStatusChartData.reduce((acc, item) => acc + item.value, 0), [pondStatusChartData])

  const pondStatusDonutBackground = useMemo(() => {
    if (pondStatusTotal <= 0) return 'conic-gradient(#e2e8f0 0deg 360deg)'
    let currentDeg = 0
    const segments = pondStatusChartData.map((item) => {
      const span = (item.value / pondStatusTotal) * 360
      const start = currentDeg
      const end = currentDeg + span
      currentDeg = end
      return `${item.color} ${start}deg ${end}deg`
    })
    return `conic-gradient(${segments.join(', ')})`
  }, [pondStatusChartData, pondStatusTotal])

  const usageStatusChartData = useMemo(() => [
    { label: 'Hoạt động', value: summary.activeUsage, color: '#14b8a6' },
    { label: 'Ngưng sử dụng', value: summary.inactiveUsage, color: '#ef4444' },
  ], [summary])

  const usageStatusTotal = useMemo(() => usageStatusChartData.reduce((acc, item) => acc + item.value, 0), [usageStatusChartData])

  const usageStatusDonutBackground = useMemo(() => {
    if (usageStatusTotal <= 0) return 'conic-gradient(#e2e8f0 0deg 360deg)'
    let currentDeg = 0
    const segments = usageStatusChartData.map((item) => {
      const span = (item.value / usageStatusTotal) * 360
      const start = currentDeg
      const end = currentDeg + span
      currentDeg = end
      return `${item.color} ${start}deg ${end}deg`
    })
    return `conic-gradient(${segments.join(', ')})`
  }, [usageStatusChartData, usageStatusTotal])

  const statusCounts = useMemo(() => {
    const map = [
      { label: 'Đang nuôi', key: 'DANG_NUOI', count: summary.farming },
      { label: 'Đang cải tạo', key: 'DANG_CAI_TAO', count: summary.renovating },
      { label: 'Tạm ngưng', key: 'TAM_NGUNG', count: summary.paused },
    ]
    return map
  }, [summary])

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize))
  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filtered.length)
  const paginated = filtered.slice(startIndex, endIndex)

  const openDetail = async (pond) => {
    try {
      const res = await pondService.getPondById(pond.pond_id)
      setSelectedPond(res?.data?.data || pond)
    } catch (err) {
      showToast({ title: 'Không tải được chi tiết ao', type: 'error' })
    }
  }

  const canConfirmRenovation = (pond) => {
    if (!pond) return false
    if (normalizeUpper(pond.status) !== 'DANG_CAI_TAO') return false
    if (normalizeUpper(pond.usage_status) === 'NGUNG_SU_DUNG') return false
    if (Number(pond.assigned_staff) !== Number(user?.user_id)) return false
    // ensure no completion recorded for current renovation
    if (pond.renovation_completed_at) return false
    return true
  }

  const handleConfirm = async (pond) => {
    if (!window.confirm(`Xác nhận hoàn tất cải tạo cho ao ${pond.pond_name}?`)) return
    try {
      await pondService.completeRenovation(pond.pond_id)
      showToast({ title: 'Xác nhận hoàn tất cải tạo thành công', type: 'success' })
      fetchData()
    } catch (err) {
      showToast({ title: err?.response?.data?.message || 'Không thể xác nhận hoàn tất', type: 'error' })
    }
  }

  if (loading) return <div className="flex-center"><div className="spinner"/></div>

  return (
    <div className="dashboard admin-page owner-ponds">
      <div className="table-container admin-users_panel">
        <div className="table-header admin-users_table-header">
          <div>
            <h2>Quản lý ao nuôi</h2>
            <p className="admin-users_subtitle">Danh sách ao bạn được phân công quản lý</p>
          </div>
        </div>

        <div className="owner-ponds_stats-grid">
          <div className="owner-ponds_stat-card owner-ponds_stat-card--total">
            <span>Tổng ao phụ trách</span>
            <strong>{summary.total}</strong>
          </div>
          <div className="owner-ponds_stat-card owner-ponds_stat-card--farming">
            <span>Ao đang nuôi</span>
            <strong>{summary.farming}</strong>
          </div>
          <div className="owner-ponds_stat-card owner-ponds_stat-card--renovating">
            <span>Ao đang cải tạo</span>
            <strong>{summary.renovating}</strong>
          </div>
          <div className="owner-ponds_stat-card owner-ponds_stat-card--paused">
            <span>Ao tạm ngưng</span>
            <strong>{summary.paused}</strong>
          </div>
          <div className="owner-ponds_stat-card owner-ponds_stat-card--active-usage">
            <span>Ao hoạt động</span>
            <strong>{summary.activeUsage}</strong>
          </div>
          <div className="owner-ponds_stat-card owner-ponds_stat-card--inactive">
            <span>Ao ngưng sử dụng</span>
            <strong>{summary.inactiveUsage}</strong>
          </div>
        </div>

        <div className="owner-ponds_charts-grid">
          <article className="owner-ponds_chart-card">
            <h4>Phân bố trạng thái ao nuôi</h4>
            <div className="owner-ponds_donut-wrap">
              <div className="owner-ponds_donut" style={{ background: pondStatusDonutBackground }}>
                <div className="owner-ponds_donut-inner">{pondStatusTotal}</div>
              </div>
              <div className="owner-ponds_legend">
                {pondStatusChartData.map((item) => (
                  <div key={item.label} className="owner-ponds_legend-item">
                    <span className="owner-ponds_legend-dot" style={{ backgroundColor: item.color }} />
                    <span>{item.label}</span>
                    <strong>{item.value}</strong>
                  </div>
                ))}
              </div>
            </div>
          </article>

          <article className="owner-ponds_chart-card">
            <h4>Phân bố trạng thái sử dụng</h4>
            <div className="owner-ponds_donut-wrap">
              <div className="owner-ponds_donut" style={{ background: usageStatusDonutBackground }}>
                <div className="owner-ponds_donut-inner">{usageStatusTotal}</div>
              </div>
              <div className="owner-ponds_legend">
                {usageStatusChartData.map((item) => (
                  <div key={item.label} className="owner-ponds_legend-item">
                    <span className="owner-ponds_legend-dot" style={{ backgroundColor: item.color }} />
                    <span>{item.label}</span>
                    <strong>{item.value}</strong>
                  </div>
                ))}
              </div>
            </div>
          </article>

          <article className="owner-ponds_chart-card">
            <h4>Số ao theo trạng thái</h4>
            <div className="owner-ponds_bars">
              {statusCounts.map((item, index) => {
                const height = `${(item.count / Math.max(1, Math.max(...statusCounts.map((c) => c.count)))) * 100}%`
                return (
                  <div key={item.key} className="owner-ponds_bar-col">
                    <div className="owner-ponds_bar" style={{ height, backgroundColor: CHART_COLORS[index % CHART_COLORS.length] }} />
                    <span className="owner-ponds_bar-value">{item.count}</span>
                    <span className="owner-ponds_bar-label">{item.label}</span>
                  </div>
                )
              })}
            </div>
          </article>
        </div>

        <div className="admin-users_toolbar owner-ponds_toolbar">
          <div className="admin-users_search-wrap">
            <span className="admin-users_search-icon">⌕</span>
            <input value={searchTerm} placeholder="Tìm theo tên ao..." onChange={(e)=>{setSearchTerm(e.target.value); setCurrentPage(1)}} />
          </div>
          <select className="admin-users_filter-select" value={statusFilter} onChange={(e)=>{setStatusFilter(e.target.value); setCurrentPage(1)}}>
            <option value="ALL">Tất cả trạng thái ao</option>
            <option value="DANG_NUOI">Đang nuôi</option>
            <option value="DANG_CAI_TAO">Đang cải tạo</option>
            <option value="TAM_NGUNG">Tạm ngưng</option>
          </select>
          <select className="admin-users_filter-select" value={usageFilter} onChange={(e)=>{setUsageFilter(e.target.value); setCurrentPage(1)}}>
            <option value="ALL">Tất cả trạng thái sử dụng</option>
            <option value="HOAT_DONG">Hoạt động</option>
            <option value="NGUNG_SU_DUNG">Ngưng sử dụng</option>
          </select>
        </div>

        <div className="table-wrapper">
          <table className="admin-users_table">
            <thead>
              <tr>
                <th>Tên ao</th>
                <th>Diện tích (m²)</th>
                <th>Độ sâu (m)</th>
                <th>Trạng thái ao</th>
                <th>Trạng thái sử dụng</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {paginated.length === 0 ? (
                <tr>
                  <td className="admin-users_empty-row" colSpan={6}>Không có dữ liệu ao phù hợp bộ lọc hiện tại.</td>
                </tr>
              ) : (
                paginated.map((pond)=>(
                  <tr key={pond.pond_id}>
                    <td>
                      <div className="owner-ponds_name-block">
                        <strong>{pond.pond_name}</strong>
                        <span>{pond.pond_code}</span>
                      </div>
                    </td>
                    <td>{formatRoundedNumber(pond.area_m2)}</td>
                    <td>{formatRoundedNumber(pond.depth_m)}</td>
                    <td><span className={getPondStatusClass(pond.status)}>{getPondStatusLabel(pond.status)}</span></td>
                    <td><span className={getUsageStatusClass(pond.usage_status)}>{getUsageStatusLabel(pond.usage_status)}</span></td>
                    <td>
                      <div className="admin-users_table-actions">
                        <button type="button" className="admin-users_action-btn admin-users_action-btn--view" title="Xem chi tiết" onClick={()=>openDetail(pond)}>ⓘ</button>
                        {canConfirmRenovation(pond) && (
                          <button type="button" className="admin-users_action-btn admin-users_action-btn--role" title="Xác nhận hoàn tất cải tạo" onClick={()=>handleConfirm(pond)}>✓</button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="admin-users_pagination">
          <div className="admin-users_pagination-left">
            <span>Số mục trên trang</span>
            <select value={pageSize} onChange={(e)=>{setPageSize(Number(e.target.value)); setCurrentPage(1)}}>
              {[5,10,20,50].map(s=> (<option key={s} value={s}>{s}</option>))}
            </select>
            <span>{filtered.length === 0 ? 0 : startIndex + 1}-{endIndex} / {filtered.length}</span>
          </div>
          <div className="admin-users_pagination-right">
            <button type="button" className="btn btn-sm btn-secondary" onClick={()=>setCurrentPage(p=>Math.max(1,p-1))} disabled={safePage<=1}>‹</button>
            <span className="admin-users_page-pill">{safePage}</span>
            <button type="button" className="btn btn-sm btn-secondary" onClick={()=>setCurrentPage(p=>Math.min(totalPages,p+1))} disabled={safePage>=totalPages}>›</button>
          </div>
        </div>
      </div>

      {selectedPond && (
        <div className="modal" onClick={()=>setSelectedPond(null)}>
          <div className="modal-content admin-users_modal admin-users_modal--detail" onClick={(e)=>e.stopPropagation()}>
            <h3>Chi tiết ao nuôi</h3>
            <div className="admin-users_detail-grid">
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Mã ao</span><strong>{selectedPond.pond_code}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Tên ao</span><strong>{selectedPond.pond_name}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Diện tích</span><strong>{formatRoundedNumber(selectedPond.area_m2)} m²</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Độ sâu</span><strong>{formatRoundedNumber(selectedPond.depth_m)} m</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Trạng thái ao</span><strong>{getPondStatusLabel(selectedPond.status)}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Trạng thái sử dụng</span><strong>{getUsageStatusLabel(selectedPond.usage_status)}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Kỹ sư phụ trách</span><strong>{selectedPond.technician_name || '-'}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Ngày tạo ao</span><strong>{formatDateTime(selectedPond.created_at)}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Bắt đầu cải tạo gần nhất</span><strong>{formatDateTime(selectedPond.renovation_started_at)}</strong></div>
              <div className="admin-users_detail-card"><span className="admin-users_detail-label">Hoàn tất cải tạo gần nhất</span><strong>{formatDateTime(selectedPond.renovation_completed_at)}</strong></div>
            </div>
            <div className="admin-users_modal-buttons admin-users_form-buttons"><button type="button" className="btn btn-secondary" onClick={()=>setSelectedPond(null)}>Đóng</button></div>
          </div>
        </div>
      )}
    </div>
  )
}

export default TechnicianPonds
